class RealTimeService {
    private io: Server;
    private pubClient: Redis;
    private subClient: Redis;

    constructor(httpServer: any) {
        this.io = new Server(httpServer, {
            cors: {
                origin: process.env.ALLOWED_ORIGINS?.split(',') || [],
                credentials: true
            },
            transports: ['websocket', 'polling'],
            pingTimeout: 60000,
            pingInterval: 25000
        });

        // Redis setup for horizontal scaling
        this.pubClient = new Redis(process.env.REDIS_URL);
        this.subClient = this.pubClient.duplicate();
        this.io.adapter(createAdapter(this.pubClient, this.subClient));

        this.setupMiddleware();
        this.setupEventHandlers();
    }

    private setupMiddleware(): void {
        // Authentication middleware
        this.io.use(async (socket, next) => {
            try {
                const token = socket.handshake.auth.token;
                const user = await WebSocketAuthenticator.verifyToken(token);
                socket.data.user = user;
                next();
            } catch (error) {
                next(new Error('Authentication error'));
            }
        });

        // Room joining based on permissions
        this.io.on('connection', (socket) => {
            const { userId, teamIds } = socket.data.user;

