    private emailQueue: Queue;
    private analyticsQueue: Queue;
    private webhookQueue: Queue;

    constructor() {
        const redisConfig = {
            redis: {
                host: process.env.REDIS_HOST,
                port: parseInt(process.env.REDIS_PORT || '6379'),
                maxRetriesPerRequest: null // Required for Bull
            }
        };

        this.emailQueue = new Queue('email', redisConfig);
        this.analyticsQueue = new Queue('analytics', redisConfig);
        this.webhookQueue = new Queue('webhook', redisConfig);

        this.setupProcessors();
        this.setupEventListeners();
    }

    private setupProcessors(): void {
        // Email processor with concurrency control
        this.emailQueue.process('send-notification', 5, async (job) => {
            const { userId, notificationType, data } = job.data;

            try {
                await this.sendEmailNotification(userId, notificationType, data);
                Logger.info('Email sent successfully', { jobId: job.id });
                return { success: true };
            } catch (error) {
                Logger.error('Failed to send email', { jobId: job.id, error });
                throw error; // Will trigger retry
            }
        });

        // Analytics processor with batching
        this.analyticsQueue.process('track-event', 1, async (job) => {
            const events = job.data.events;
            await this.batchInsertAnalytics(events);
        });

        // Webhook processor with exponential backoff
        this.webhookQueue.process('send-webhook', 3, async (job) => {
            const { url, payload, webhookId } = job.data;

            const response = await fetch(url, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(payload),
                timeout: 5000
            });

            if (!response.ok) {
                throw new Error(`Webhook failed with status: ${response.status}`);
