### 5. Request Context Propagation
For distributed tracing and logging in Linear's microservices:
```typescript
import { AsyncLocalStorage } from 'async_hooks';
import { v4 as uuidv4 } from 'uuid';

interface RequestContext {
    requestId: string;
    userId?: string;
    sessionId?: string;
    startTime: number;
    path: string;
    method: string;
}

class RequestContextManager {
    private static asyncLocalStorage = new AsyncLocalStorage<RequestContext>();

    static createMiddleware() {
        return (req: any, res: any, next: any) => {
            const context: RequestContext = {
                requestId: req.headers['x-request-id'] || uuidv4(),
                userId: req.user?.id,
                sessionId: req.session?.id,
                startTime: Date.now(),
                path: req.path,
                method: req.method
            };

            // Store context in AsyncLocalStorage
            this.asyncLocalStorage.run(context, () => {
                // Add request ID to response headers
                res.setHeader('X-Request-ID', context.requestId);

                // Log request start
                Logger.info('Request started', {
                    requestId: context.requestId,
                    method: context.method,
                    path: context.path
                });

                // Hook response finish for logging
                res.on('finish', () => {
                    const duration = Date.now() - context.startTime;
                    Logger.info('Request completed', {
                        requestId: context.requestId,
                        method: context.method,
                        path: context.path,
                        statusCode: res.statusCode,
                        duration
                    });
                });

                next();
            });
        };
    }

    static getCurrentContext(): RequestContext | undefined {
        return this.asyncLocalStorage.getStore();
    }

    static getRequestId(): string {
        return this.getCurrentContext()?.requestId || 'unknown';
    }
}

// Logger that automatically includes request context
class Logger {
    static info(message: string, meta: any = {}) {
        const context = RequestContextManager.getCurrentContext();
        const logEntry = {
            timestamp: new Date().toISOString(),
            level: 'INFO',
            message,
            requestId: context?.requestId,
            userId: context?.userId,
            ...meta
        };

        console.log(JSON.stringify(logEntry));
    }

    static error(message: string, error?: any, meta: any = {}) {
        const context = RequestContextManager.getCurrentContext();
        const logEntry = {
            timestamp: new Date().toISOString(),
            level: 'ERROR',
            message,
            requestId: context?.requestId,
            userId: context?.userId,
            error: error?.message,
            stack: error?.stack,
            ...meta
        };

        console.error(JSON.stringify(logEntry));
    }
}

