### 2. Real-time Architecture with WebSockets
Linear's real-time features need persistent connections. API Gateway WebSocket API with Lambda or ECS backend:

```typescript
// WebSocket connection handler
export const handler = async (event) => {
  const { connectionId, routeKey } = event.requestContext;

  switch (routeKey) {
    case '$connect':
      // Store connection in DynamoDB with user context
      await dynamodb.put({
        TableName: process.env.CONNECTIONS_TABLE,
        Item: {
          connectionId,
          userId: event.queryStringParameters?.userId,
          connectedAt: Date.now(),
          ttl: Math.floor(Date.now() / 1000) + 3600 // 1 hour TTL
        }
      });
      break;

    case '$disconnect':
      await dynamodb.delete({ 
        TableName: process.env.CONNECTIONS_TABLE,
        Key: { connectionId }
      });
      break;

    case 'subscribeIssue':
      // Add connection to issue subscription
      const { issueId } = JSON.parse(event.body);
      await dynamodb.update({
        TableName: process.env.SUBSCRIPTIONS_TABLE,
        Key: { issueId },
        UpdateExpression: 'ADD connections :c',
        ExpressionAttributeValues: { ':c': dynamodb.createSet([connectionId]) }
      });
      break;
  }

  return { statusCode: 200 };
};

// Broadcasting updates
export const notifyIssueUpdate = async (issueId, update) => {
  const result = await dynamodb.get({
    TableName: process.env.SUBSCRIPTIONS_TABLE,
    Key: { issueId }
  });

  if (result.Item?.connections) {
    const apiGateway = new AWS.ApiGatewayManagementApi({
      endpoint: process.env.WS_ENDPOINT
    });

    await Promise.all(
      Array.from(result.Item.connections).map(async (connectionId) => {
        try {
          await apiGateway.postToConnection({
            ConnectionId: connectionId,
            Data: JSON.stringify({ type: 'ISSUE_UPDATE', payload: update })
          }).promise();
        } catch (err) {
          // Connection may have closed - clean up
          if (err.statusCode === 410) {
            await dynamodb.update({
              TableName: process.env.SUBSCRIPTIONS_TABLE,
              Key: { issueId },
              UpdateExpression: 'DELETE connections :c',
              ExpressionAttributeValues: { ':c': dynamodb.createSet([connectionId]) }
            });
          }
        }
      })
    );
  }
};
```

### 3. Database Pattern with RDS PostgreSQL
For Linear's PostgreSQL at scale, use RDS with read replicas and connection pooling:

```typescript
// Using environment-based configuration for different endpoints
const { Pool } = require('pg');

// Primary writer pool
const writerPool = new Pool({
  host: process.env.DB_WRITER_ENDPOINT,
  max: 20, // Match RDS instance size (connections = (DBInstanceClassMemory / 12582880) * 0.75)
  idleTimeoutMillis: 30000,
  connectionTimeoutMillis: 2000,
});

// Reader pool for replicas
const readerPool = new Pool({
  host: process.env.DB_READER_ENDPOINT, // RDS read replica endpoint
  max: 50, // Can have more connections to readers
});

// Route reads to replicas, writes to primary
class DatabaseRouter {
  async query(sql, params, isWrite = false) {
    const pool = isWrite ? writerPool : readerPool;
    const client = await pool.connect();

    try {
      const start = Date.now();
      const result = await client.query(sql, params);
      const duration = Date.now() - start;

      // Log slow queries
      if (duration > 1000) {
        console.warn('Slow query', { sql, duration });
      }

      return result;
    } finally {
      client.release();
    }
  }
}

